const tiktokData = $('Fetch My TikTok Videos').first().json;
const ytVideos = $('Fetch YouTube Channel Videos').first().json;
const ytStats = $('Fetch YouTube Video Stats').first().json;
const igData = $('Fetch Instagram Media').first().json;

const results = [];

// TikTok
try {
  for (const v of (tiktokData.data?.videos || []).slice(0, 20)) {
    const views = v.stats?.playCount || 1;
    const likes = v.stats?.diggCount || 0;
    const comments = v.stats?.commentCount || 0;
    const shares = v.stats?.shareCount || 0;
    const engRate = ((likes + comments + shares) / views * 100).toFixed(2);
    const score = Math.min(100, Math.round((parseFloat(engRate) * 10) + (views / 10000)));
    results.push({
      videoTitle: (v.desc || 'TikTok Video').substring(0, 100),
      platform: 'TikTok',
      views, likes, comments, shares,
      engagementRate: parseFloat(engRate),
      watchTimePercent: 0,
      postedAt: v.createTime ? new Date(v.createTime * 1000).toISOString() : new Date().toISOString(),
      performanceScore: score,
      contentType: 'Short'
    });
  }
} catch(e) {}

// YouTube
try {
  const statsMap = {};
  for (const s of (ytStats.items || [])) {
    statsMap[s.id] = s.statistics;
  }
  for (const v of (ytVideos.items || []).slice(0, 20)) {
    const vid = v.id?.videoId;
    const st = statsMap[vid] || {};
    const views = parseInt(st.viewCount || 0);
    const likes = parseInt(st.likeCount || 0);
    const comments = parseInt(st.commentCount || 0);
    const engRate = views ? ((likes + comments) / views * 100).toFixed(2) : 0;
    const score = Math.min(100, Math.round((parseFloat(engRate) * 10) + (views / 10000)));
    results.push({
      videoTitle: (v.snippet?.title || 'YouTube Video').substring(0, 100),
      platform: 'YouTube',
      views, likes, comments, shares: 0,
      engagementRate: parseFloat(engRate),
      watchTimePercent: 0,
      postedAt: v.snippet?.publishedAt || new Date().toISOString(),
      performanceScore: score,
      contentType: 'Short'
    });
  }
} catch(e) {}

// Instagram
try {
  for (const p of (igData.data || []).slice(0, 20)) {
    const likes = p.like_count || 0;
    const comments = p.comments_count || 0;
    const engRate = ((likes + comments) / 1000 * 100).toFixed(2);
    const score = Math.min(100, Math.round(parseFloat(engRate) * 5));
    results.push({
      videoTitle: (p.caption || 'Instagram Post').substring(0, 100),
      platform: 'Instagram',
      views: 0, likes, comments, shares: 0,
      engagementRate: parseFloat(engRate),
      watchTimePercent: 0,
      postedAt: p.timestamp || new Date().toISOString(),
      performanceScore: score,
      contentType: p.media_type === 'VIDEO' ? 'Reel' : 'Carousel'
    });
  }
} catch(e) {}

return results.map(r => ({ json: r }));
